class SensitiveDataFilter(logging.Filter):
    """
    Filter that redacts potentially sensitive data from log messages.
    Prevents accidental logging of passwords, tokens, SSNs, credit card numbers, etc.
    """
    
    import re
    
    SENSITIVE_PATTERNS = [
        # Credit card numbers (basic pattern)
        (re.compile(r'\b(?:\d{4}[-\s]?){3}\d{4}\b'), '[REDACTED_CC]'),
        # SSN pattern
        (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '[REDACTED_SSN]'),
        # Email addresses
        (re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'), '[REDACTED_EMAIL]'),
        # Common password/secret key patterns in key=value format
        (re.compile(r'(?i)(password|passwd|pwd|secret|token|api_key|apikey|auth)\s*[=:]\s*\S+'), r'\1=[REDACTED]'),
        # Bearer tokens
        (re.compile(r'(?i)Bearer\s+[A-Za-z0-9\-._~+/]+=*'), 'Bearer [REDACTED]'),
    ]
    
    def filter(self, record):
        if isinstance(record.msg, str):
            message = record.msg
            for pattern, replacement in self.SENSITIVE_PATTERNS:
                message = pattern.sub(replacement, message)
            record.msg = message
        
        # Also filter args if they are strings
        if record.args:
            if isinstance(record.args, dict):
                filtered_args = {}
                for key, value in record.args.items():
                    if isinstance(value, str):
                        for pattern, replacement in self.SENSITIVE_PATTERNS:
                            value = pattern.sub(replacement, value)
                    filtered_args[key] = value
                record.args = filtered_args
            elif isinstance(record.args, tuple):
                filtered_args = []
                for arg in record.args:
                    if isinstance(arg, str):
                        for pattern, replacement in self.SENSITIVE_PATTERNS:
                            arg = pattern.sub(replacement, arg)
                    filtered_args.append(arg)
                record.args = tuple(filtered_args)
        
        return True


class SecureRotatingFileHandler(logging.handlers.RotatingFileHandler):
    """
    Extended RotatingFileHandler that ensures rotated files also have
    secure permissions.
    """
    
    def doRollover(self):
        """Override to set secure permissions on newly created rotated files."""
        old_umask = os.umask(0o177)
        try:
            super().doRollover()
        finally:
            os.umask(old_umask)
        
        # Set permissions on the new log file
        if os.path.exists(self.baseFilename):
            os.chmod(self.baseFilename, stat.S_IRUSR | stat.S_IWUSR)
        
        # Set permissions on rotated files
        for i in range(1, self.backupCount + 1):
            rotated = f"{self.baseFilename}.{i}"
            if os.path.exists(rotated) and not os.path.islink(rotated):
                os.chmod(rotated, stat.S_IRUSR | stat.S_IWUSR)


def verify_log_security(log_dir):
    """Verify that log files and directory have secure permissions."""
    issues = []
    
    # Check directory permissions
    dir_stat = os.stat(log_dir)
    dir_mode = stat.S_IMODE(dir_stat.st_mode)
    if dir_mode & (stat.S_IRGRP | stat.S_IWGRP | stat.S_IXGRP |
                   stat.S_IROTH | stat.S_IWOTH | stat.S_IXOTH):
        issues.append(
            f"Directory '{log_dir}' has overly permissive permissions: "
            f"{oct(dir_mode)}. Expected 0o700."
        )
    
    # Check each file in the directory
    for filename in os.listdir(log_dir):
        filepath = os.path.join(log_dir, filename)
        
        if os.path.islink(filepath):
            issues.append(f"Symlink detected: '{filepath}'. Potential security risk.")
            continue
        
        if os.path.isfile(filepath):
            file_stat = os.stat(filepath)
            file_mode = stat.S_IMODE(file_stat.st_mode)
            if file_mode & (stat.S_IRGRP | stat.S_IWGRP |
                           stat.S_IROTH | stat.S_IWOTH):
                issues.append(
                    f"File '{filepath}' has overly permissive permissions: "
                    f"{oct(file_mode)}. Expected 0o600."
                )
    
    return issues


